     1→frappe.ui.form.on('BOM Upload', {
     2→    create_boms(frm) {
     3→        if (!frm.doc.bom_file) {
     4→            frappe.msgprint("Please attach a BOM Excel file first.");
     5→            return;
     6→        }
     7→
     8→        frappe.call({
     9→            method: 'clevertech.clevertech.doctype.bom_upload.bom_upload.create_boms',
    10→            args: {
    11→                docname: frm.doc.name
    12→            },
    13→            freeze: true,
    14→            freeze_message: __('Creating BOMs...'),
    15→            callback(r) {
    16→                if (!r.message) {
    17→                    frappe.msgprint({
    18→                        title: __('Error'),
    19→                        message: __('No response from server'),
    20→                        indicator: 'red'
    21→                    });
    22→                    return;
    23→                }
    24→
    25→                const msg = r.message;
    26→                let error_html = '';
    27→
    28→                if (msg.errors && msg.errors.length > 0) {
    29→                    error_html = '<br><br><strong>Errors:</strong><br>' + msg.errors.join('<br>');
    30→                }
    31→
    32→                frappe.msgprint({
    33→                    title: __('BOM Import Result'),
    34→                    message: `
    35→                        <strong>BOMs Created:</strong> ${msg.created}<br>
    36→                        <strong>BOMs Skipped:</strong> ${msg.skipped}<br>
    37→                        <strong>Failed:</strong> ${msg.failed}
    38→                        ${error_html}
    39→                    `,
    40→                    indicator: msg.failed > 0 ? 'orange' : 'green'
    41→                });
    42→
    43→                frm.reload_doc();
    44→            },
    45→            error(r) {
    46→                frappe.msgprint({
    47→                    title: __('Error'),
    48→                    message: __('Failed to create BOMs. Please check the error log.'),
    49→                    indicator: 'red'
    50→                });
    51→            }
    52→        });
    53→    },
    54→
    55→    create_boms_with_validation(frm) {
    56→        if (!frm.doc.bom_file) {
    57→            frappe.msgprint("Please attach a BOM Excel file first.");
    58→            return;
    59→        }
    60→
    61→        if (!frm.doc.project) {
    62→            frappe.msgprint("Please select a Project first.");
    63→            return;
    64→        }
    65→
    66→        frappe.call({
    67→            method: 'clevertech.clevertech.doctype.bom_upload.bom_upload_enhanced.create_boms_with_validation',
    68→            args: {
    69→                docname: frm.doc.name
    70→            },
    71→            freeze: true,
    72→            freeze_message: __('Analyzing BOM upload...'),
    73→            callback(r) {
    74→                if (!r.message) {
    75→                    frappe.msgprint({
    76→                        title: __('Error'),
    77→                        message: __('No response from server'),
    78→                        indicator: 'red'
    79→                    });
    80→                    return;
    81→                }
    82→
    83→                const result = r.message;
    84→                console.log("BOM Upload Result:", JSON.stringify(result, null, 2));
    85→
    86→                if (result.status === 'blocked') {
    87→                    _show_loose_items_blocked_dialog(result);
    88→                }
    89→                else if (result.status === 'procurement_blocked') {
    90→                    _show_procurement_block_dialog(result, frm);
    91→                }
    92→                else if (result.status === 'manager_required') {
    93→                    _show_manager_required_dialog(result);
    94→                }
    95→                else if (result.status === 'requires_confirmation') {
    96→                    _show_confirmation_dialog(result, frm);
    97→                }
    98→                else if (result.status === 'requires_resolution') {
    99→                    // Legacy fallback - should not hit this with new logic
   100→                    _show_change_resolution_dialog(result.analysis, frm);
   101→                }
   102→                else if (result.status === 'success') {
   103→                    _show_upload_success(result);
   104→                    frm.reload_doc();
   105→                }
   106→            },
   107→            error(r) {
   108→                frappe.msgprint({
   109→                    title: __('Error'),
   110→                    message: __('Failed to process BOM upload. Check error log.'),
   111→                    indicator: 'red'
   112→                });
   113→            }
   114→        });
   115→    },
   116→
   117→    debug_bom_quantities(frm) {
   118→        if (!frm.doc.bom_file) {
   119→            frappe.msgprint("Please attach a BOM Excel file first.");
   120→            return;
   121→        }
   122→
   123→        // Prompt for target item code
   124→        frappe.prompt(
   125→            {
   126→                label: 'Target Item Code',
   127→                fieldname: 'target_item',
   128→                fieldtype: 'Data',
   129→                description: 'Leave empty to auto-select most frequent item'
   130→            },
   131→            function(values) {
   132→                frappe.call({
   133→                    method: 'clevertech.clevertech.doctype.bom_upload.bom_upload_enhanced.debug_bom_quantities',
   134→                    args: {
   135→                        docname: frm.doc.name,
   136→                        target_item_code: values.target_item || null
   137→                    },
   138→                    freeze: true,
   139→                    freeze_message: __('Analyzing BOM quantities...'),
   140→                    callback(r) {
   141→                        if (!r.message) {
   142→                            frappe.msgprint({
   143→                                title: __('Error'),
   144→                                message: __('No response from server'),
   145→                                indicator: 'red'
   146→                            });
   147→                            return;
   148→                        }
   149→
   150→                        _show_debug_results(r.message);
   151→                    },
   152→                    error(r) {
   153→                        frappe.msgprint({
   154→                            title: __('Error'),
   155→                            message: __('Failed to analyze quantities. Check error log.'),
   156→                            indicator: 'red'
   157→                        });
   158→                    }
   159→                });
   160→            },
   161→            __('Debug BOM Quantities'),
   162→            __('Analyze')
   163→        );
   164→    }
   165→});
