   168→// ==================== Dialog Functions ====================
   169→
   170→function _show_loose_items_blocked_dialog(data) {
   171→    let items_html = '';
   172→    if (data.analysis && data.analysis.loose_blocked) {
   173→        items_html = data.analysis.loose_blocked.map(function(item) {
   174→            return '<li><b>' + (item.node ? item.node.item_code : 'Unknown') + '</b>'
   175→                + ' - ' + (item.details ? item.details.message : 'Conversion not enabled')
   176→                + '<br><small>Go to Project Component Master to enable conversion</small></li>';
   177→        }).join('');
   178→    }
   179→
   180→    let html = '<div class="alert alert-danger">'
   181→        + '<h5><i class="fa fa-lock"></i> Loose Items Blocking BOM Creation</h5>'
   182→        + '<p>The following loose items must have "Can be converted to BOM" enabled first:</p>'
   183→        + '<ul>' + items_html + '</ul>'
   184→        + '</div>';
   185→
   186→    frappe.msgprint({
   187→        title: __('Upload Blocked'),
   188→        message: html,
   189→        indicator: 'red',
   190→        primary_action: {
   191→            label: __('Open Component Master List'),
   192→            action: function() {
   193→                frappe.set_route('List', 'Project Component Master', {
   194→                    'is_loose_item': 1
   195→                });
   196→            }
   197→        }
   198→    });
   199→}
   200→
   201→function _show_change_resolution_dialog(analysis, frm) {
   202→    let changed_components = analysis.changed_components || [];
   203→    let blocked_components = analysis.blocked_by_dependencies || {};
   204→    let summary = analysis.summary || {};
   205→
   206→    let changed_html = '';
   207→    if (changed_components.length > 0) {
   208→        changed_html = '<div class="changed-components" style="margin-bottom:20px">'
   209→            + '<h6 class="text-warning"><i class="fa fa-exclamation-triangle"></i> Changed Components Requiring Resolution:</h6>';
   210→
   211→        changed_components.forEach(function(comp, idx) {
   212→            let node = comp.node || {};
   213→            let details = comp.details || {};
   214→            let procurement_html = '';
   215→
   216→            if (details.procurement_status && details.procurement_status.length > 0) {
   217→                procurement_html = '<div class="alert alert-warning">'
   218→                    + '<b><i class="fa fa-warning"></i> Active Procurement:</b>'
   219→                    + '<ul style="margin:5px 0 0 20px">'
   220→                    + details.procurement_status.map(function(doc) {
   221→                        return '<li>' + doc.doctype + ': ' + doc.name + ' (' + doc.status + ')</li>';
   222→                    }).join('')
   223→                    + '</ul></div>';
   224→            }
   225→
   226→            changed_html += '<div class="card mb-3" style="border-left:3px solid #ffa00a;padding:10px;margin-bottom:10px">'
   227→                + '<h6>[' + (idx + 1) + '/' + changed_components.length + '] ' + node.item_code + '</h6>'
   228→                + '<p><b>Change Type:</b> ' + (details.change_type || 'Unknown') + '</p>'
   229→                + '<p><b>Old BOM:</b> '
   230→                + (details.old_bom
   231→                    ? '<a href="/app/bom/' + details.old_bom + '">' + details.old_bom + '</a>'
   232→                    : 'None')
   233→                + '</p>'
   234→                + procurement_html
   235→                + '<p class="text-muted"><small><i class="fa fa-info-circle"></i> '
   236→                + 'Action: Deactivate old BOM manually, then re-run upload</small></p>'
   237→                + '</div>';
   238→        });
   239→
   240→        changed_html += '</div>';
   241→    }
   242→
   243→    let blocked_html = '';
   244→    let blocked_keys = Object.keys(blocked_components);
   245→    if (blocked_keys.length > 0) {
   246→        blocked_html = '<div class="blocked-components">'
   247→            + '<h6 class="text-danger"><i class="fa fa-ban"></i> Components Blocked by Dependencies:</h6>'
   248→            + '<ul>';
   249→
   250→        blocked_keys.forEach(function(item) {
   251→            let reasons = blocked_components[item] || [];
   252→            blocked_html += '<li><b>' + item + '</b><ul style="margin-left:20px">';
   253→            reasons.forEach(function(r) {
   254→                blocked_html += '<li>' + r.item + ': ' + r.reason + '</li>';
   255→            });
   256→            blocked_html += '</ul></li>';
   257→        });
   258→
   259→        blocked_html += '</ul></div>';
   260→    }
   261→
   262→    let html = '<div class="bom-change-resolution">'
   263→        + '<h5><i class="fa fa-warning"></i> BOM Upload Analysis</h5>'
   264→        + '<div class="summary" style="margin:15px 0">'
   265→        + '<table class="table table-bordered table-sm">'
   266→        + '<tr class="text-success"><td><i class="fa fa-check"></i> Can Create Immediately:</td>'
   267→        + '<td><b>' + (summary.can_create || 0) + '</b> components</td></tr>'
   268→        + '<tr class="text-warning"><td><i class="fa fa-exclamation-triangle"></i> Changed Components:</td>'
   269→        + '<td><b>' + (summary.changed || 0) + '</b> components</td></tr>'
   270→        + '<tr class="text-danger"><td><i class="fa fa-ban"></i> Blocked by Dependencies:</td>'
   271→        + '<td><b>' + (summary.blocked || 0) + '</b> components</td></tr>'
   272→        + '</table></div>'
   273→        + changed_html
   274→        + blocked_html
   275→        + '<hr>'
   276→        + '<div class="alert alert-info">'
   277→        + '<h6><i class="fa fa-lightbulb-o"></i> Next Steps:</h6>'
   278→        + '<ol style="margin:10px 0 0 20px">'
   279→        + '<li>Review changed components above</li>'
   280→        + '<li>Deactivate old BOMs in BOM List</li>'
   281→        + '<li>Re-run "Create BOMs with Validation" to complete upload</li>'
   282→        + '</ol></div>'
   283→        + '</div>';
   284→
   285→    let d = new frappe.ui.Dialog({
   286→        title: __('BOM Changes Detected - Resolution Required'),
   287→        fields: [
   288→            {
   289→                fieldtype: 'HTML',
   290→                fieldname: 'analysis_html',
   291→                options: html
   292→            }
   293→        ],
   294→        size: 'large',
   295→        primary_action_label: __('Open BOM List'),
   296→        primary_action: function() {
   297→            let item_codes = changed_components.map(function(c) {
   298→                return c.node ? c.node.item_code : '';
   299→            }).filter(function(c) { return c; });
   300→
   301→            frappe.set_route('List', 'BOM', {
   302→                'item': ['in', item_codes],
   303→                'is_active': 1
   304→            });
   305→            d.hide();
   306→        }
   307→    });
   308→
   309→    d.show();
   310→}
   311→
   312→function _show_upload_success(result) {
   313→    let errors_html = '';
   314→    if (result.errors && result.errors.length > 0) {
   315→        errors_html = '<hr><h6 class="text-danger"><i class="fa fa-exclamation-triangle"></i> Errors:</h6>'
   316→            + '<ul>' + result.errors.map(function(e) { return '<li>' + e + '</li>'; }).join('') + '</ul>';
   317→    }
   318→
   319→    // Extract summary data (supports both old and new format)
   320→    let summary = result.summary || {};
   321→    let items = summary.items || {};
   322→    let boms = summary.boms || {};
   323→    let cms = summary.component_masters || {};
   324→
   325→    // Build comprehensive summary table
   326→    let html = '<div class="alert alert-success">'
   327→        + '<h5><i class="fa fa-check-circle"></i> BOM Upload Complete</h5>';
   328→
   329→    // User-friendly message if provided
   330→    if (result.message) {
   331→        html += '<p class="text-muted" style="margin:10px 0">' + result.message + '</p>';
   332→    }
   333→
   334→    html += '<div class="row" style="margin-top:15px">';
   335→
   336→    // Items column
   337→    if (items.total > 0) {
   338→        html += '<div class="col-md-4">'
   339→            + '<h6><i class="fa fa-shopping-cart"></i> Items</h6>'
   340→            + '<table class="table table-sm table-bordered">'
   341→            + '<tr class="table-success"><td>Created</td><td><b>' + (items.created || 0) + '</b></td></tr>'
   342→            + '<tr class="table-secondary"><td>Already Existed</td><td><b>' + (items.existing || 0) + '</b></td></tr>';
   343→        if (items.updated > 0) {
   344→            html += '<tr class="table-warning"><td>Updated</td><td><b>' + items.updated + '</b></td></tr>';
   345→        }
   346→        if (items.failed > 0) {
   347→            html += '<tr class="table-danger"><td>Failed</td><td><b>' + items.failed + '</b></td></tr>';
   348→        }
   349→        html += '<tr class="table-info"><td><b>Total</b></td><td><b>' + (items.total || 0) + '</b></td></tr>'
   350→            + '</table></div>';
   351→    }
   352→
   353→    // BOMs column
   354→    if (boms.total > 0) {
   355→        html += '<div class="col-md-4">'
   356→            + '<h6><i class="fa fa-sitemap"></i> BOMs</h6>'
   357→            + '<table class="table table-sm table-bordered">'
   358→            + '<tr class="table-success"><td>Created</td><td><b>' + (boms.created || 0) + '</b></td></tr>'
   359→            + '<tr class="table-secondary"><td>Already Existed</td><td><b>' + (boms.existing || 0) + '</b></td></tr>';
   360→        if (boms.failed > 0) {
   361→            html += '<tr class="table-danger"><td>Failed</td><td><b>' + boms.failed + '</b></td></tr>';
   362→        }
   363→        html += '<tr class="table-info"><td><b>Total</b></td><td><b>' + (boms.total || 0) + '</b></td></tr>'
   364→            + '</table></div>';
   365→    }
   366→
   367→    // Component Masters column
   368→    if (cms.total > 0) {
   369→        html += '<div class="col-md-4">'
   370→            + '<h6><i class="fa fa-cube"></i> Component Masters</h6>'
   371→            + '<table class="table table-sm table-bordered">'
   372→            + '<tr class="table-success"><td>Created</td><td><b>' + (cms.created || 0) + '</b></td></tr>'
   373→            + '<tr class="table-secondary"><td>Already Existed</td><td><b>' + (cms.existing || 0) + '</b></td></tr>';
   374→        if (cms.updated > 0) {
   375→            html += '<tr class="table-warning"><td>Updated</td><td><b>' + cms.updated + '</b></td></tr>';
   376→        }
   377→        if (cms.failed > 0) {
   378→            html += '<tr class="table-danger"><td>Failed</td><td><b>' + cms.failed + '</b></td></tr>';
   379→        }
   380→        html += '<tr class="table-info"><td><b>Total</b></td><td><b>' + (cms.total || 0) + '</b></td></tr>'
   381→            + '</table></div>';
   382→    }
   383→
   384→    html += '</div>' // Close row
   385→        + errors_html
   386→        + '</div>';
   387→
   388→    frappe.msgprint({
   389→        title: __('Success'),
   390→        message: html,
   391→        indicator: 'green',
   392→        wide: true
   393→    });
   394→}
