   397→// ==================== Phase 4E: Tiered Blocking Dialogs ====================
   398→
   399→function _show_procurement_block_dialog(result, frm) {
   400→    // Hard block - MR/RFQ exists, user must deactivate old BOM manually
   401→    let blocked = result.blocked_components || [];
   402→
   403→    let docs_html = '';
   404→    blocked.forEach(function(comp) {
   405→        let details = comp.details || {};
   406→        let procurement_docs = details.procurement_docs || [];
   407→
   408→        docs_html += '<div class="card mb-3" style="border-left:3px solid #dc3545;padding:10px;margin-bottom:10px">'
   409→            + '<h6><i class="fa fa-ban text-danger"></i> ' + comp.item_code + '</h6>'
   410→            + '<p class="text-muted">' + (details.blocking_message || 'Has active procurement') + '</p>';
   411→
   412→        if (procurement_docs.length > 0) {
   413→            docs_html += '<table class="table table-sm table-bordered">'
   414→                + '<thead><tr><th>Document</th><th>Item</th><th>Qty</th><th>Status</th></tr></thead>'
   415→                + '<tbody>';
   416→            procurement_docs.forEach(function(doc) {
   417→                docs_html += '<tr>'
   418→                    + '<td><a href="/app/' + frappe.router.slug(doc.doctype) + '/' + doc.name + '">'
   419→                    + doc.doctype + ': ' + doc.name + '</a></td>'
   420→                    + '<td>' + (doc.item_code || '-') + '</td>'
   421→                    + '<td>' + (doc.quantity || '-') + '</td>'
   422→                    + '<td>' + (doc.status || '-') + '</td>'
   423→                    + '</tr>';
   424→            });
   425→            docs_html += '</tbody></table>';
   426→        }
   427→
   428→        docs_html += '</div>';
   429→    });
   430→
   431→    let html = '<div class="bom-procurement-block">'
   432→        + '<div class="alert alert-danger">'
   433→        + '<h5><i class="fa fa-lock"></i> BOM Change Blocked</h5>'
   434→        + '<p>Cannot change BOM structure because child items have active Material Requests or RFQs.</p>'
   435→        + '</div>'
   436→        + docs_html
   437→        + '<hr>'
   438→        + '<div class="alert alert-info">'
   439→        + '<h6><i class="fa fa-lightbulb-o"></i> To Proceed:</h6>'
   440→        + '<ol style="margin:10px 0 0 20px">'
   441→        + '<li>Go to BOM List</li>'
   442→        + '<li>Deactivate the old BOM(s) listed above</li>'
   443→        + '<li>Re-run "Create BOMs with Validation"</li>'
   444→        + '</ol></div>'
   445→        + '</div>';
   446→
   447→    let d = new frappe.ui.Dialog({
   448→        title: __('BOM Change Blocked - Active Procurement'),
   449→        fields: [
   450→            {
   451→                fieldtype: 'HTML',
   452→                fieldname: 'block_html',
   453→                options: html
   454→            }
   455→        ],
   456→        size: 'large',
   457→        primary_action_label: __('Open BOM List'),
   458→        primary_action: function() {
   459→            let item_codes = blocked.map(function(c) { return c.item_code; });
   460→            frappe.set_route('List', 'BOM', {
   461→                'item': ['in', item_codes],
   462→                'is_active': 1
   463→            });
   464→            d.hide();
   465→        }
   466→    });
   467→
   468→    d.show();
   469→}
   470→
