   472→function _show_manager_required_dialog(result) {
   473→    // PO exists but user lacks manager role
   474→    let blocked = result.blocked_components || [];
   475→
   476→    let docs_html = '';
   477→    blocked.forEach(function(comp) {
   478→        let details = comp.details || {};
   479→        let procurement_docs = details.procurement_docs || [];
   480→
   481→        // Filter to only show POs
   482→        let pos = procurement_docs.filter(function(d) {
   483→            return d.doctype === 'Purchase Order';
   484→        });
   485→
   486→        docs_html += '<div class="card mb-3" style="border-left:3px solid #dc3545;padding:10px;margin-bottom:10px">'
   487→            + '<h6><i class="fa fa-ban text-danger"></i> ' + comp.item_code + '</h6>';
   488→
   489→        if (pos.length > 0) {
   490→            docs_html += '<p><b>Active Purchase Orders:</b></p>'
   491→                + '<ul>';
   492→            pos.forEach(function(doc) {
   493→                docs_html += '<li><a href="/app/purchase-order/' + doc.name + '">'
   494→                    + doc.name + '</a> - ' + (doc.item_code || '') + ' (Qty: ' + (doc.quantity || 0) + ')</li>';
   495→            });
   496→            docs_html += '</ul>';
   497→        }
   498→
   499→        docs_html += '</div>';
   500→    });
   501→
   502→    let html = '<div class="bom-manager-required">'
   503→        + '<div class="alert alert-danger">'
   504→        + '<h5><i class="fa fa-user-times"></i> Manager Role Required</h5>'
   505→        + '<p>Cannot change BOM structure because child items have active <b>Purchase Orders</b>.</p>'
   506→        + '<p>Only users with <b>Component Master Manager</b> or <b>System Manager</b> role can override this.</p>'
   507→        + '</div>'
   508→        + docs_html
   509→        + '<hr>'
   510→        + '<div class="alert alert-warning">'
   511→        + '<h6><i class="fa fa-info-circle"></i> Options:</h6>'
   512→        + '<ol style="margin:10px 0 0 20px">'
   513→        + '<li>Contact a manager to perform the upload</li>'
   514→        + '<li>Or manually deactivate the old BOM(s), then re-run upload</li>'
   515→        + '</ol></div>'
   516→        + '</div>';
   517→
   518→    frappe.msgprint({
   519→        title: __('Manager Role Required'),
   520→        message: html,
   521→        indicator: 'red'
   522→    });
   523→}
