   526→function _show_confirmation_dialog(result, frm) {
   527→    // No hard block - just need confirmation with remarks
   528→    let confirmable = result.confirmable_components || [];
   529→
   530→    // Build fields for each component requiring confirmation
   531→    let fields = [
   532→        {
   533→            fieldtype: 'HTML',
   534→            fieldname: 'intro_html',
   535→            options: '<div class="alert alert-warning">'
   536→                + '<h5><i class="fa fa-exclamation-triangle"></i> BOM Structure Changed</h5>'
   537→                + '<p>The following components have changed BOM structure. '
   538→                + 'Enter remarks to confirm each change.</p></div>'
   539→        }
   540→    ];
   541→
   542→    confirmable.forEach(function(comp, idx) {
   543→        let details = comp.details || {};
   544→        let has_po = details.blocking_level === 'manager_required';
   545→
