   563→                + '<b style="font-size:12px">Changes:</b>';
   564→
   565→            if (bom_diff.added && bom_diff.added.length > 0) {
   566→                section_html += '<div style="color:#28a745;font-size:11px;margin-top:4px">'
   567→                    + '<b>+ Added:</b> ';
   568→                section_html += bom_diff.added.map(function(i) {
