function _show_debug_bom_qty_dialog(rows) {
    let html = '<table class="table table-bordered table-sm" style="font-size:11px">'
        + '<thead><tr>'
        + '<th>Level</th><th>Item Code</th><th>Make/Buy</th>'
        + '<th>DB proj_qty</th><th>DB bom_qty_req</th><th>DB total_qty</th>'
        + '<th>CALC bom_qty_req</th><th>CALC total_qty</th>'
        + '<th>Match?</th><th>Detail</th>'
        + '</tr></thead><tbody>';

    rows.forEach(function(row) {
        let match_bom = (parseFloat(row.db_bom_qty_required) === parseFloat(row.calc_bom_qty_required));
        let match_tql = (parseFloat(row.db_total_qty_limit) === parseFloat(row.calc_total_qty_limit));
        let match = match_bom && match_tql;

        let row_class = row.calc_error ? 'table-danger'
            : (!match ? 'table-warning' : '');

        // Build usage detail
        let detail = row.calc_note || '';
        if (row.bom_usage && row.bom_usage.length > 0) {
            detail = row.bom_usage.map(function(u) {
                if (!u.parent_found) {
                    return '<span class="text-danger"><b>PARENT NOT FOUND</b> lookup: '
                        + JSON.stringify(u.parent_lookup_filter) + '</span>';
                }
                return u.calc_detail + ' (parent=' + u.parent_item + ')';
            }).join('<br>');
        }
        if (row.calc_error) {
            detail = '<span class="text-danger">ERROR: ' + row.calc_error + '</span>';
        }

        html += '<tr class="' + row_class + '">'
            + '<td>' + (row.level || '-') + '</td>'
            + '<td><b>' + row.item_code + '</b></td>'
            + '<td>' + (row.db_make_or_buy || '-') + '</td>'
            + '<td>' + row.db_project_qty + '</td>'
            + '<td>' + row.db_bom_qty_required + '</td>'
            + '<td>' + row.db_total_qty_limit + '</td>'
            + '<td><b>' + row.calc_bom_qty_required + '</b></td>'
            + '<td><b>' + row.calc_total_qty_limit + '</b></td>'
            + '<td>' + (match ? '✓' : '<span class="text-danger"><b>✗</b></span>') + '</td>'
            + '<td style="max-width:300px">' + detail + '</td>'
            + '</tr>';
    });

    html += '</tbody></table>';

    let d = new frappe.ui.Dialog({
        title: __('Debug: bom_qty_required Recalculation'),
        fields: [{
            fieldtype: 'HTML',
            fieldname: 'debug_html',
            options: '<div style="margin-bottom:10px">'
                + '<span class="indicator-pill green">✓ DB matches calc</span> '
                + '<span class="indicator-pill orange">✗ Mismatch</span> '
                + '<span class="indicator-pill red">Error</span>'
                + '</div>' + html
        }],
        size: 'extra-large'
    });
    d.show();
}

